{"command":"$ErrorActionPreference='SilentlyContinue'
$exports = @()
$codexRoot = Join-Path $HOME '.codex\sessions'
if (Test-Path $codexRoot) {
  $codex = Get-ChildItem -Path $codexRoot -Recurse -Filter *.jsonl | Sort-Object LastWriteTime -Descending | Select-Object -First 1
  if ($codex) { Copy-Item -LiteralPath $codex.FullName -Destination (Join-Path (Get-Location) 'codex-session.jsonl') -Force; $exports += "codex-session.jsonl <- $($codex.FullName)" }
}
$claudeRoot = Join-Path $HOME '.claude\projects'
if (Test-Path $claudeRoot) {
  $claude = Get-ChildItem -Path $claudeRoot -Recurse -Filter *.jsonl | Sort-Object LastWriteTime -Descending | Select-Object -First 1
  if ($claude) { Copy-Item -LiteralPath $claude.FullName -Destination (Join-Path (Get-Location) 'claude-session.jsonl') -Force; $exports += "claude-session.jsonl <- $($claude.FullName)" }
}
if ($exports.Count -eq 0) { 'NO_SESSION_EXPORTS_FOUND' } else { $exports -join "`n" }","workdir":"C:\Users\yyash\Coding\Solsmile","timeout_ms":30000}
